def ComposeResult(order: Optional[dict], error: Optional[str], stock_restored: bool, refunded: bool, status_updated: bool) -> dict:
    if error:
        return {"success": False, "message": error}
    else:
        details = []
        if stock_restored:
            details.append("Stock restored")
        if refunded:
            details.append("Refund processed")
        if status_updated:
            details.append("Status updated")
        message = ", ".join(details) if details else "No actions performed"
        return {"success": True, "message": message}

def handle_cancel_order(order_data: dict) -> dict:
    order, error = ValidateOrder(order_data)
    if error:
        return ComposeResult(order, error, False, False, False)
    stock_restored = RestoreStock(order)
    refunded = RefundIfPaid(order)
    status_updated = UpdateOrderStatus(order)
    return ComposeResult(order, None, stock_restored, refunded, status_updated)

